const { ethers } = require("ethers");

async function main() {
    // Connect to the Ethereum network using MetaMask provider
    const provider = new ethers.providers.Web3Provider(window.ethereum);
    await provider.send("eth_requestAccounts", []);
    const signer = provider.getSigner();

    // Define the addresses for ERC20 tokens and DEX contract
    const tokenAAddress = "TOKEN_A_ADDRESS";
    const tokenBAddress = "TOKEN_B_ADDRESS";
    const dexAddress = "DEX_CONTRACT_ADDRESS";

    // ABI for ERC20 tokens (example, adjust according to your token)
    const erc20Abi = [
        "function approve(address spender, uint256 amount) returns (bool)",
        "function allowance(address owner, address spender) view returns (uint256)"
    ];

    // ABI for DEX contract (example, adjust according to your DEX)
    const dexAbi = [
        "function swapExactTokensForTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) external returns (uint256[] memory amounts)",
    ];

    // Create contract instances
    const tokenA = new ethers.Contract(tokenAAddress, erc20Abi, signer);
    const tokenB = new ethers.Contract(tokenBAddress, erc20Abi, signer);
    const dex = new ethers.Contract(dexAddress, dexAbi, signer);

    // Function to approve maximum uint256 amount for a token
    async function approveToken(tokenContract) {
        const maxAmount = ethers.constants.MaxUint256;
        const allowance = await tokenContract.allowance(await signer.getAddress(), dexAddress);
        if (allowance.lt(maxAmount)) {
            const tx = await tokenContract.approve(dexAddress, maxAmount);
            await tx.wait();
            console.log("Approval successful");
        } else {
            console.log("Max allowance already set");
        }
    }

    // Function to swap tokens
    async function swapTokens(amountIn) {
        const path = [tokenA.address, tokenB.address];
        const amountOutMin = 1; // Minimum amount of output tokens you are willing to accept
        const deadline = Math.floor(Date.now() / 1000) + 60 * 20; // Deadline for the transaction

        const tx = await dex.swapExactTokensForTokens(amountIn, amountOutMin, path, signer.getAddress(), deadline);
        await tx.wait();
        console.log("Swap successful");
    }

    // Example usage
    try {
        await approveToken(tokenA);
        const amountIn = ethers.utils.parseUnits("10", 18); // Amount of token A to swap (example: 10 tokens)
        await swapTokens(amountIn);
    } catch (error) {
        console.error("Error:", error);
    }
}

